import * as admin from "firebase-admin";
import * as functions from "firebase-functions";
import * as path from "path";

admin.initializeApp();

// Store the Next.js request handler
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let nextHandler: any = null;
let initPromise: Promise<void> | null = null;

/**
 * Initialize Next.js server from standalone build
 */
async function initializeNextServer() {
  if (nextHandler) {
    return;
  }

  if (initPromise) {
    await initPromise;
    return;
  }

  initPromise = (async () => {
    try {
      // Load the standalone server.js
      const serverPath = path.join(__dirname, "..", ".next-standalone", "server.js");
      // eslint-disable-next-line global-require
      // eslint-disable-next-line @typescript-eslint/no-var-requires
      const {default: server} = require(serverPath);
      nextHandler = server;
      console.log("Next.js server initialized");
    } catch (error) {
      console.error("Failed to initialize Next.js server:", error);
      throw error;
    }
  })();

  await initPromise;
}

/**
 * Cloud Function that serves the Next.js app
 */
export const nextApp = functions.https.onRequest(async (req, res) => {
  try {
    // Initialize on first request
    if (!nextHandler) {
      await initializeNextServer();
    }

    if (!nextHandler) {
      res.status(503).json({error: "Service unavailable"});
      return;
    }

    // Forward request to Next.js server
    nextHandler(req, res);
  } catch (error) {
    console.error("Error serving Next.js:", error);
    res.status(500).json({error: "Internal server error"});
  }
});

import * as admin from "firebase-admin";
import * as functions from "firebase-functions";
import * as path from "path";

admin.initializeApp();

// Store the Next.js request handler
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let nextHandler: any = null;
let initPromise: Promise<void> | null = null;

/**
 * Initialize Next.js server from standalone build
 */
async function initializeNextServer() {
  if (nextHandler) {
    return;
  }

  if (initPromise) {
    await initPromise;
    return;
  }

  initPromise = (async () => {
    try {
      // Load the standalone server.js
      const serverPath = path.join(
        __dirname,
        "..",
        ".next-standalone",
        "server.js",
      );
      // eslint-disable-next-line global-require
      // eslint-disable-next-line @typescript-eslint/no-var-requires
      const {default: server} = require(serverPath);
      nextHandler = server;
      console.log("Next.js server initialized");
    } catch (error) {
      console.error("Failed to initialize Next.js server:", error);
      throw error;
    }
  })();

  await initPromise;
}

/**
 * Cloud Function that serves the Next.js app
 */
export const nextApp = functions.https.onRequest(async (req, res) => {
  try {
    // Initialize on first request
    if (!nextHandler) {
      await initializeNextServer();
    }

    if (!nextHandler) {
      res.status(503).json({error: "Service unavailable"});
      return;
    }

    // Forward request to Next.js server
    nextHandler(req, res);
  } catch (error) {
    console.error("Error serving Next.js:", error);
    res.status(500).json({error: "Internal server error"});
  }
});

:host {
  --svg-frame-image: none;
  --svg-frame-color: #d7dde3;
  --accent-color: #d7dde3;
  --text-color: #4f555b;
  --card-bg: rgba(255, 255, 255, 0.96);
  --card-border: rgba(212, 218, 225, 0.92);
  --card-text: #4c5259;
  --viewport-height: 100vh;
  --controls-height: 50px;
}

@supports (height: 100dvh) {
  :host {
    --viewport-height: 100dvh;
  }
}

.invitation-page {
  position: relative;
  width: 100%;
  height: var(--viewport-height);
  background: #fcfdff;
  color: var(--text-color);
  font-family: var(--font-body, sans-serif), sans-serif;
  line-height: 1.6;
  overflow: hidden;
}

.page-background {
  position: fixed;
  inset: 0;
  color: var(--svg-frame-color);
  background-color: currentColor;
  -webkit-mask-image: var(--svg-frame-image);
  mask-image: var(--svg-frame-image);
  -webkit-mask-size: cover;
  mask-size: cover;
  -webkit-mask-position: center;
  mask-position: center;
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  z-index: 0;
}

@media (min-width: 1024px) and (orientation: landscape) {
  .page-background {
    inset: auto;
    left: 50%;
    top: 50%;
    width: 100vh;
    height: 100vw;
    transform: translate(-50%, -50%) rotate(90deg);
    transform-origin: center;
    -webkit-mask-size: contain;
    mask-size: contain;
  }
}

.page-content {
  position: relative;
  width: 100%;
  height: var(--viewport-height);
  overflow: hidden;
  z-index: 2;
}


.slides-shell {
  position: relative;
  z-index: 3;
  width: 100%;
  height: var(--viewport-height);
  overflow: hidden;
  overscroll-behavior: none;
  -webkit-user-select: none;
  user-select: none;
  touch-action: none;
}

.slides-track {
  display: flex;
  width: 100%;
  height: calc(var(--viewport-height) - var(--controls-height) - env(safe-area-inset-bottom, 0px));
  transition: transform 420ms ease;
  will-change: transform;
}

.slide-page {
  flex: 0 0 100%;
  width: 100%;
  height: 100%;
  display: flex;
  justify-content: center;
}

.slide-scroll {
  width: min(700px, 100%);
  height: 100%;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0.8rem;
  box-sizing: border-box;
}

.slide-scroll.intro-scroll {
  flex-direction: column;
  gap: 0.4rem;
}

.slide-card {
  width: 100%;
  max-width: 650px;
  max-height: 100%;
  overflow: hidden;
  border-radius: 20px;
  color: var(--card-text);
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  box-shadow: 0 10px 30px rgba(36, 44, 55, 0.08);
}

.slide-page.rsvp-slide .slide-scroll {
  align-items: stretch;
}

.slide-page.rsvp-slide .slide-card.scrollable-card {
  height: 100%;
  overflow-y: auto;
  overscroll-behavior: contain;
  -webkit-overflow-scrolling: touch;
}

.intro-card {
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 0.85rem 0;
}

.slide-controls {
  height: calc(var(--controls-height) + env(safe-area-inset-bottom, 0px));
  display: flex;
  align-items: center;
  justify-content: center;
  padding-bottom: env(safe-area-inset-bottom, 0px);
  background: transparent;
  position: relative;
  z-index: 3;
}

.music-control {
  position: absolute;
  bottom: 1.25rem;
  left: 1.25rem;
  z-index: 1001;
  width: 42px;
  height: 42px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.95);
  border: 1px solid rgba(212, 218, 225, 0.95);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 6px 18px rgba(36, 44, 55, 0.12);
}

.music-control svg {
  width: 1.1rem;
  height: 1.1rem;
  color: #8e959e;
  opacity: 0.9;
}

.music-control.playing {
  border-color: #bfc7d0;
}

.slide-dots {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  background: rgba(255, 255, 255, 0.94);
  border-radius: 999px;
  border: 1px solid rgba(212, 218, 225, 0.9);
  box-shadow: 0 6px 18px rgba(36, 44, 55, 0.1);
}

.dot {
  width: 8px;
  height: 8px;
  border-radius: 999px;
  border: 0;
  padding: 0;
  background: #c7ced6;
  cursor: pointer;
  transition: transform 200ms ease, background-color 200ms ease, width 200ms ease;
  flex-shrink: 0;
}

.dot.active {
  background: #aab3be;
  width: 22px;
}

.swipe-hint {
  padding: 0.75rem 0 0.5rem;
  font-size: 0.74rem;
  color: #8c949d;
  opacity: 0.95;
  letter-spacing: 0.07em;
  text-align: center;
  text-transform: uppercase;
  flex-shrink: 0;
}

@media (max-width: 768px) {
  .slide-page.rsvp-slide .slide-scroll {
    align-items: center;
  }

  .slide-card,
  .slide-page.rsvp-slide .slide-card.scrollable-card {
    height: 70%;
    max-height: 70%;
    overflow-y: auto;
    overscroll-behavior: contain;
    -webkit-overflow-scrolling: touch;
  }

  .slide-card {
    border-radius: 16px;
  }
}

@media (max-width: 480px) {

  .dot {
    width: 6px;
    height: 6px;
  }

  .dot.active {
    width: 18px;
  }

  .slide-scroll {
    padding: 0.5rem;
  }

  .slide-card {
    border-radius: 14px;
  }
}

@media print {
  .page-background {
    display: none;
  }
}

@media (prefers-contrast: more) {
  .invitation-page {
    color: #2b2f33;
  }

  .slide-card {
    border-width: 2px;
  }
}

@media (prefers-reduced-motion: reduce) {
  * {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

@media (prefers-color-scheme: dark) {
  .invitation-page {
    background-color: #f6f7f9;
    color: #3f464d;
  }
}

