:root {
  --font-body: sans-serif;
  --font-display: cursive;
  --font-accent: sans-serif;
  --font-highlight: sans-serif;
  --font-quote: serif;
  --surface-glass: linear-gradient(160deg, rgba(255, 255, 255, 0.96), rgba(250, 251, 252, 0.92));
  --surface-border: 1px solid rgba(216, 222, 228, 0.88);
  --surface-shadow: 0 10px 24px rgba(36, 44, 55, 0.08);
}

html,
body {
  height: 100%;
  margin: 0;
  font-family: var(--font-body, sans-serif), sans-serif;
}

body {
  background-color: #fcfdff;
}

* {
  transition-property: background-color, border-color, color, box-shadow;
  transition-duration: 0.28s;
  transition-timing-function: ease;
}

@keyframes invitationFadeInUp {
  from {
    opacity: 0;
    transform: translateY(12px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.invitation-page {
  --slide-padding: 1.25rem;
  --slide-gap: 1rem;
  --content-primary: #4b525a;
  --content-soft: rgba(75, 82, 90, 0.78);
}

.invitation-page .event-section,
.invitation-page .registry-section,
.invitation-page .rsvp-section,
.invitation-page .thank-you-section,
.invitation-page .timeline-section {
  width: 100%;
  min-height: 100%;
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: var(--slide-gap);
  padding: var(--slide-padding);
  box-sizing: border-box;
  animation: invitationFadeInUp 500ms ease-out both;
  color: var(--content-primary);
}

.invitation-page .section-header {
  text-align: center;
  margin-bottom: 0.4rem;
}

.invitation-page .section-title {
  font-family: var(--font-display, cursive), cursive;
  font-size: clamp(2rem, 8vw, 3rem);
  font-weight: 400;
  letter-spacing: 0.01em;
  line-height: 1.1;
  margin: 0 0 0.5rem;
  text-wrap: balance;
  color: #495058;
}

.invitation-page .section-description {
  max-width: 38ch;
  margin: 0 auto;
  font-size: 0.92rem;
  color: var(--content-soft);
  line-height: 1.55;
  text-wrap: pretty;
}

.invitation-page .section-kicker,
.invitation-page .deadline,
.invitation-page .form-label,
.invitation-page .date-label,
.invitation-page .countdown-label,
.invitation-page .countdown-unit {
  font-family: var(--font-accent, sans-serif), sans-serif;
  text-transform: uppercase;
  letter-spacing: 0.09em;
}

.invitation-page .section-kicker {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 30px;
  padding: 0.25rem 0.8rem;
  border-radius: 999px;
  border: 1px solid rgba(216, 222, 228, 0.9);
  background: #ffffff;
  font-size: 0.58rem;
  color: #6e767f;
}

.invitation-page .event-item,
.invitation-page .registry-card,
.invitation-page .response-summary,
.invitation-page .countdown-item,
.invitation-page .timeline-image-wrapper {
  background: var(--surface-glass);
  border-radius: 16px;
  box-shadow: var(--surface-shadow);
}

.invitation-page .event-item,
.invitation-page .registry-card,
.invitation-page .choice-button,
.invitation-page .map-button,
.invitation-page .copy-button {
  transition: transform 220ms ease, border-color 220ms ease, background-color 220ms ease;
}

.invitation-page .map-button,
.invitation-page .copy-button,
.invitation-page .choice-button,
.invitation-page .submit-button,
.invitation-page .form-select,
.invitation-page .form-textarea {
  border-radius: 16px;
}

.invitation-page .map-button,
.invitation-page .copy-button,
.invitation-page .choice-button,
.invitation-page .form-select,
.invitation-page .form-textarea {
  /*border: 1px solid rgba(216, 222, 228, 0.95);*/
  background: #ffffff;
  color: var(--content-primary);
}

.invitation-page .submit-button {
  font-family: var(--font-body, sans-serif), sans-serif;
  font-weight: 700;
}

@media (hover: hover) and (pointer: fine) {
  .invitation-page .event-item:hover,
  .invitation-page .registry-card:hover {
    background: #ffffff;
    border-color: rgba(201, 209, 217, 0.95);
    transform: translateY(-2px);
  }
}

@media (max-width: 768px) {
  .invitation-page {
    --slide-padding: 1rem;
    --slide-gap: 0.9rem;
  }
}

@media (max-width: 420px) {
  .invitation-page .section-kicker {
    font-size: 0.54rem;
  }
}

