.invitation-page .section-title {
  font-family: var(--font-display, cursive), cursive;
  font-size: clamp(2rem, 8vw, 3rem);
  font-weight: 400;
  letter-spacing: 0.01em;
  line-height: 1.1;
  margin: 0 0 0.5rem;
  text-wrap: balance;
  color: #495058;
}

.invitation-page .section-description {
  max-width: 38ch;
  margin: 0 auto;
  font-size: 0.92rem;
  color: var(--content-soft);
  line-height: 1.55;
  text-wrap: pretty;
}

.invitation-page .section-kicker,
.invitation-page .deadline,
.invitation-page .form-label,
.invitation-page .date-label,
.invitation-page .countdown-label,
.invitation-page .countdown-unit {
  font-family: var(--font-accent, sans-serif), sans-serif;
  text-transform: uppercase;
  letter-spacing: 0.09em;
}

.invitation-page .section-kicker {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 30px;
  padding: 0.25rem 0.8rem;
  border-radius: 999px;
  border: 1px solid rgba(216, 222, 228, 0.9);
  background: #ffffff;
  font-size: 0.58rem;
  color: #6e767f;
}

.invitation-page .event-item,
.invitation-page .registry-card,
.invitation-page .response-summary,
.invitation-page .countdown-item,
.invitation-page .timeline-image-wrapper {
  background: var(--surface-glass);
  border-radius: 16px;
  box-shadow: var(--surface-shadow);
}

.invitation-page .event-item,
.invitation-page .registry-card,
.invitation-page .choice-button,
.invitation-page .map-button,
.invitation-page .copy-button {
  transition: transform 220ms ease, border-color 220ms ease, background-color 220ms ease;
}

.invitation-page .map-button,
.invitation-page .copy-button,
.invitation-page .choice-button,
.invitation-page .submit-button,
.invitation-page .form-select,
.invitation-page .form-textarea {
  border-radius: 16px;
}

.invitation-page .map-button,
.invitation-page .copy-button,
.invitation-page .choice-button,
.invitation-page .form-select,
.invitation-page .form-textarea {
  /*border: 1px solid rgba(216, 222, 228, 0.95);*/
  background: #ffffff;
  color: var(--content-primary);
}

.invitation-page .submit-button {
  font-family: var(--font-body, sans-serif), sans-serif;
  font-weight: 700;
}

@media (hover: hover) and (pointer: fine) {
  .invitation-page .event-item:hover,
  .invitation-page .registry-card:hover {
    background: #ffffff;
    border-color: rgba(201, 209, 217, 0.95);
    transform: translateY(-2px);
  }
}

@media (max-width: 768px) {
  .invitation-page {
    --slide-padding: 1rem;
    --slide-gap: 0.9rem;
  }
}

@media (max-width: 420px) {
  .invitation-page .section-kicker {
    font-size: 0.54rem;
  }
}
